#include <iostream>
#include <vector>
#include <climits>

using namespace std;

int minSubArrayLen(int target, vector<int> &nums)
{
    int n = nums.size();
    int best = INT_MAX;

    for (int i = 0; i < n; i++)
    {
        int sum = 0;
        for (int j = i; j < n; j++)
        {
            sum += nums[j];
            if (sum >= target)
            {
                best = min(best, j - i + 1);
                break;
            }
        }
    }

    return (best == INT_MAX) ? 0 : best;
}

int main()
{
    vector<int> nums = {2, 3, 1, 2, 4, 3};

    cout << minSubArrayLen(7, nums) << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <climits>

using namespace std;

int minSubArrayLen(int target, vector<int> &nums)
{
    int left = 0;
    int sum = 0;
    int best = INT_MAX;

    for (int right = 0; right < nums.size(); right++)
    {
        sum += nums[right];

        while (sum >= target)
        {
            best = min(best, right - left + 1);
            sum -= nums[left];
            left++;
        }
    }

    return (best == INT_MAX) ? 0 : best;
}

int main()
{
    vector<int> nums = {2, 3, 1, 2, 4, 3};

    cout << minSubArrayLen(7, nums) << endl;

    return 0;
}

#include <iostream>
#include <string>
#include <unordered_set>

using namespace std;

bool hasRepeat(string &s, int i, int j)
{
    unordered_set<char> seen;
    for (int k = i; k <= j; k++)
    {
        if (seen.count(s[k])) return true;
        seen.insert(s[k]);
    }
    return false;
}

int lengthOfLongestSubstring(string s)
{
    int best = 0;

    for (int i = 0; i < s.size(); i++)
    {
        for (int j = i; j < s.size(); j++)
        {
            if (!hasRepeat(s, i, j)) best = max(best, j - i + 1);
        }
    }

    return best;
}

int main()
{
    cout << lengthOfLongestSubstring("abcabcbb") << endl;

    return 0;
}

#include <iostream>
#include <string>
#include <unordered_set>

using namespace std;

int lengthOfLongestSubstring(string s)
{
    unordered_set<char> window;
    int left = 0;
    int best = 0;

    for (int right = 0; right < s.size(); right++)
    {
        while (window.count(s[right]))
        {
            window.erase(s[left]);
            left++;
        }

        window.insert(s[right]);
        best = max(best, right - left + 1);
    }

    return best;
}

int main()
{
    cout << lengthOfLongestSubstring("abcabcbb") << endl;

    return 0;
}

